float2 uv = (UV - 0.5) * Zoom;
float t = Time;

// Animate center drift on beat
float2 center = float2(
    -0.7269 + sin(t * 0.07) * 0.002 + Beat * 0.008,
    0.1889 + cos(t * 0.05) * 0.002
);

float2 c = uv + center;
float2 z = float2(0, 0);

float iter = 0.0;
float smoothColor = 0.0;
int maxI = (int)clamp(MaxIter, 8.0, 128.0);
float pw = clamp(Power, 2.0, 16.0);

for(int i = 0; i < 128; i++) {
    if(i >= maxI) break;
    if(dot(z, z) > 4.0) break;

    // Standard Mandelbrot z = z^2 + c (with power param morphing)
    float zr = z.x, zi = z.y;
    float r2 = dot(z, z);
    float theta = atan2(zi, zr) * pw;
    float rpow = pow(max(r2, 0.0001), pw * 0.5);
    z.x = rpow * cos(theta) + c.x;
    z.y = rpow * sin(theta) + c.y;
    iter = (float)i;
}

bool escaped = dot(z, z) > 4.0;
// Smooth iteration count (Bernstein smoothing)
float sl = iter - log2(log2(dot(z,z))) + 4.0;
float t2 = frac(sl * 0.1 + t * 0.05);

float3 col = float3(0, 0, 0);
if(escaped) {
    // Multi-stop palette: deep purple → teal → gold → white
    float3 c0 = float3(0.1, 0.02, 0.2);
    float3 c1 = PrimaryColor.rgb;  // teal/palette
    float3 c2 = AccentColor.rgb;   // gold
    float3 c3 = float3(1.0, 0.98, 0.95); // near white

    float3 mapped;
    if(t2 < 0.33) mapped = lerp(c0, c1, t2 * 3.0);
    else if(t2 < 0.66) mapped = lerp(c1, c2, (t2 - 0.33) * 3.0);
    else mapped = lerp(c2, c3, (t2 - 0.66) * 3.0);

    col = mapped * (0.7 + sl * 0.015);

    // Edge sparkle near boundary
    float edgeness = saturate(1.0 - sl * 0.04);
    float sparkle = edgeness * SparkleIntensity * (sin(sl * 12.7 + t * 3.0) * 0.5 + 0.5);
    col += float3(1, 1, 1) * sparkle * 0.5;
} else {
    // Interior: dark pulse on beat
    col = float3(0.02, 0.01, 0.04) * (1.0 + Beat * 0.3);
}

col *= EmissiveBoost;
return float4(col, 1.0);
